// uniform float exampleUniform;

// Values come in as a texture
// these constants are which pixel row the values are stored in
const int LENS = 0;
const int WIDTH = 1;
const int HEIGHT = 2;
const int CROPWIDTH = 3;
const int CROPHEIGHT = 4;
const int FOV = 5;
const int YAW = 6;
const int PITCH = 7;
const int ROLL = 8;
const int A = 9;
const int B = 10;
const int C = 11;
const int SHIFTX = 12;
const int SHIFTY = 13;
const int SHEARX = 14;
const int SHEARY = 15;
const int CROPLEFT = 16;
const int CROPRIGHT = 17;
const int CROPBOTTOM = 18;
const int CROPTOP = 19;


uniform vec4 uCropOutput;
uniform float uBlendExp;
uniform samplerBuffer uMuteDeact;

#include <genUVFisheye>
#include <genUVRectilinear>


out vec4 fragColor;

void main()
{
	vec4 colors[TD_NUM_2D_INPUTS-1];
	float weights[TD_NUM_2D_INPUTS-1];
	float sourceWeights[TD_NUM_2D_INPUTS-1];
	float weightSum = 0.0;
	bool allZeroSource = true;
	bool multiBlend = false;
	bool allZeroExp = true;
	int singleBlendIndex = 0;
	vec4 uvB = vec4(0.0);
	for (int i = 0; i < TD_NUM_2D_INPUTS - 1; i += 1)
	{
		vec2 muteDeact = texelFetch(uMuteDeact, i).rg;
		float lens = texelFetch(sTD2DInputs[0], ivec2(i,LENS), 0).r;
		if (lens != 0.0){
			uvB = fisheye(vUV.st, i);
		}else{
			uvB = rectlinear(vUV.st, i);
		}
		uvB.p = min(uvB.p + muteDeact.g,1.0);
		uvB.p = max(uvB.p - muteDeact.r,0.0);
		uvB.p *= uvB.a;

		colors[i] = texture(sTD2DInputs[i+1], uvB.st);

		sourceWeights[i] = uvB.p;

		if (uvB.p != 0.0)
		{	
			singleBlendIndex = i;
			multiBlend = !allZeroSource;
			allZeroSource = false;
			uvB.p = pow(uvB.p, uBlendExp);
			if (uvB.p != 0.0)
			{
				allZeroExp = false;
			}
		}

		weights[i] = uvB.p;
		weightSum += uvB.p;

	}
	if (allZeroSource)
	{
		fragColor = vec4(0.0);
	}
	else
	{
		vec3 sum = vec3(0.0);
		if (multiBlend)
		{
			if (allZeroExp)
			{
				int num = 0;
				for (int i = 0; i < TD_NUM_2D_INPUTS - 1; i++)
				{	
					if (sourceWeights[i] != 0.0)
					{
						num++;
						sum.rgb += colors[i].rgb;
					}
				}
				sum.rgb /= float(num);

			}
			else
			{
				for (int i = 0; i < TD_NUM_2D_INPUTS - 1; i++)
				{	
					if (weights[i] != 0.0)
					{
						sum.rgb += colors[i].rgb * (weights[i] / weightSum);
					}
				}
			}
		}
		else
		{
			sum.rgb += colors[singleBlendIndex].rgb;
		}
		fragColor = vec4(sum, 1.0);
	}

}

