mat3 rotateOnAxis(float radians, vec3 axis) {
    float c = cos(radians);
    float s = sin(radians);
    float x = axis.x;
    float y = axis.y;
    float z = axis.z;
    mat3 rot;

    // row 0\n";
    rot[0][0] = pow(x,2.0) * (1.0-c) + c;
    rot[1][0] = x*y*(1.0-c)-z*s;
    rot[2][0] = x*z*(1.0-c)+y*s;

    // row 1\n";
    rot[0][1] = y*x*(1.0-c)+z*s;
    rot[1][1] = pow(y,2.0) * (1.0 - c)+c;
    rot[2][1] = y*z*(1.0-c)-x*s;

    rot[0][2] = x*z*(1.0-c)-y*s;
    rot[1][2] = y*z*(1.0-c)+x*s;
    rot[2][2] = pow(z,2.0)*(1.0-c)+c;
    return rot;

}


vec4 fisheye(vec2 uvIn, int img)
{

#define PI 3.14159265358979
	vec3 spherePos;
	float theta, phi;

	vec2 uv = uvIn.st;
	uv.s *= (uCropOutput.t - uCropOutput.s) / 360.0;
	uv.s += uCropOutput.s / 360.0;
	uv.t *= (uCropOutput.q - uCropOutput.p) / 180.0;
	uv.t += uCropOutput.p / 180.0;

	theta = 2.0 * PI * (uv.s - 0.5);
	phi = PI * (uv.t - 0.5);

	spherePos.x = cos(phi) * sin(theta);
	spherePos.y = cos(phi) * cos(theta);
	spherePos.z = sin(phi);

	// Yes this looks correct, it starts at X+ and wraps 
	// towards the right
	spherePos = normalize(spherePos);

	// Apply rotation to the position here
	mat3 rotMat;

	float yaw = texelFetch(sTD2DInputs[0], ivec2(img, YAW), 0).r;
	float pitch = texelFetch(sTD2DInputs[0], ivec2(img, PITCH), 0).r;
	float roll = texelFetch(sTD2DInputs[0], ivec2(img, ROLL), 0).r;

	rotMat = rotateOnAxis(radians(yaw) , vec3(0, 0, 1));
	spherePos = rotMat * spherePos;

	rotMat = rotateOnAxis(radians(-pitch) , vec3(1, 0, 0));
	spherePos = rotMat * spherePos;

	rotMat = rotateOnAxis(radians(-roll) , vec3(0, 1, 0));
	spherePos = rotMat * spherePos;

	// now convert to fisheye coordinate from
	// http://paulbourke.net/papers/bangalore2012/bangaloreslides.pdf
	// however this function assumes the fisheye is 180 degrees
	// which we arn't getting

	vec3 psph = spherePos;

	theta = atan(psph.z, psph.x);
	phi = atan(length(psph.xz), psph.y);

	// phi is the distance from the center of the fisheye
	// to the outer edge, it goes from [0, PI]
	// theta is the angle around the fisheye, it
	// goes from [-PI, PI]
	float fov = radians(texelFetch(sTD2DInputs[0], ivec2(img, FOV), 0).r); 
	float r = phi / (fov / 2);

	// lens correction, taken from
	// http://www.ptgui.com/ptguihelp/main_lens.htm
	float rdst = r;
	float origRDst = rdst;
	float a = texelFetch(sTD2DInputs[0], ivec2(img, A), 0).r;
	float b = texelFetch(sTD2DInputs[0], ivec2(img, B), 0).r;
	float c = texelFetch(sTD2DInputs[0], ivec2(img, C), 0).r;

	r = (1 - a - b - c) * rdst;
	rdst *= origRDst;
	r += c * rdst;
	rdst *= origRDst;
	r += b * rdst;
	rdst *= origRDst;
	r += a * rdst;


	if (abs(r - origRDst) < 1.0 && abs(r) <= 1.0)
	{
		uv.s = r * cos(theta);
		uv.t = r * sin(theta);

		// apply shear
		uv += vec2(uv.t * (texelFetch(sTD2DInputs[0], ivec2(img, SHEARX), 0).r / float(texelFetch(sTD2DInputs[0], ivec2(img, CROPWIDTH), 0).r)), uv.s * (-texelFetch(sTD2DInputs[0], ivec2(img, SHEARY), 0).r / float(texelFetch(sTD2DInputs[0], ivec2(img, CROPHEIGHT), 0).r)));

		uv *= 0.5;
		uv += 0.5;

		// crop the image
		float cropLeft = texelFetch(sTD2DInputs[0], ivec2(img, CROPLEFT), 0).r;
		float cropRight = texelFetch(sTD2DInputs[0], ivec2(img, CROPRIGHT), 0).r;
		float cropBottom = texelFetch(sTD2DInputs[0], ivec2(img, CROPBOTTOM), 0).r;
		float cropTop = texelFetch(sTD2DInputs[0], ivec2(img, CROPTOP), 0).r;
		float width = texelFetch(sTD2DInputs[0], ivec2(img, WIDTH), 0).r;
		float height = texelFetch(sTD2DInputs[0], ivec2(img, HEIGHT), 0).r;

		cropLeft /= width;
		cropRight /= width;
		cropBottom = (height - cropBottom) / height;
		cropTop = (height - cropTop) / height;

		uv.x = cropLeft + uv.x * (cropRight - cropLeft);
		uv.y = cropBottom + uv.y * (cropTop - cropBottom);

		// shift and make sure to clamp it
		uv.x += texelFetch(sTD2DInputs[0], ivec2(img, SHIFTX), 0).r / width * -1.0;
		uv.y += texelFetch(sTD2DInputs[0], ivec2(img, SHIFTY), 0).r/ height;

		if (uv.x > 1 || uv.y > 1 || uv.x < 0 || uv.y < 0)
		{
			return vec4(0.0);
		}

		return vec4(uv, 1.0 - clamp(abs(r), 0.0, 1.0), 1);
	}
	else
	{
		return vec4(0);
	}


}

