// Example Pixel Shader

// uniform float exampleUniform;

uniform float uFOV;
uniform vec3 uABC;
uniform float yaw;
uniform float pitch;
uniform float roll;
uniform vec2 uShift;
uniform vec2 uShear;
uniform vec2 uCropRes;
uniform vec4 uCropOutput;
uniform vec4 uCropTexture;

out vec4 fragColor;


vec3 IntersectPlane(vec3 ray, vec3 N, vec3 botLeft)
{
    vec3 D = ray;
    vec3 X = D * dot(botLeft, N) / dot(D, N);

    return X;
}

vec2
applyLensDistortion(float a, float b, float c, vec2 p, float aspectRatio)
{
	vec2 lensP = p.xy;

	// Lens distoration is done with a radius == 1.0 circle that fits within
	// the image. So the radius of the smaller dimension is 1.0.
	// So we need to convert to this space to do the lens distortion by
	// leaving the smaller dimension alone, and scaling the larger one up
	if (aspectRatio > 1.0)
	{
		lensP.x *= aspectRatio;
	}
	else if (aspectRatio < 1.0)
	{
		lensP.y /= aspectRatio;
	}

	float curLen = length(lensP.xy);
	float rdst = curLen;

	// Same thing as:
	// float adjustedLen = a * pow(rdst, 4.0) + b * pow(rdst, 3.0) + c * pow(rdst, 2.0) + (1 - (a + b + c)) * rdst;
	// but avoids pow()
	float origRDst = rdst;
	float r = (1 - a - b - c) * rdst;
	rdst *= origRDst;
	r += c * rdst;
	rdst *= origRDst;
	r += b * rdst;
	rdst *= origRDst;
	r += a * rdst;
	float adjustedLen = r;


	// If the len difference is massive, then this is is a point way outside the area of interest
	// so don't adjust it
	if (abs(adjustedLen - curLen) > 1)
		return p;

	lensP *= adjustedLen / curLen;

	// Now convert back to the original space, which is [-1,1] in both dimensions
	if (aspectRatio > 1.0)
	{
		lensP.x /= aspectRatio;
	}
	else if (aspectRatio < 1.0)
	{
		lensP.y *= aspectRatio;
	}	

	p.xy = lensP;
	return p;

}


void main()
{
	vec2 res = uCropRes.xy;

	// pitch = X
	// yaw = Y
	// roll = Z
	mat3 rot = TDRotateY(radians(-(yaw - 90))) * TDRotateX(radians(pitch)) * TDRotateZ(radians(-roll));

	vec2 uv = vUV.st;
	uv.s *= (uCropOutput.t - uCropOutput.s) / 360.0;
	uv.s += uCropOutput.s / 360.0;
	uv.t *= (uCropOutput.q - uCropOutput.p) / 180.0;
	uv.t += uCropOutput.p / 180.0;


	// Determine the direction in 3D space we are currently looking at
	vec3 n = TDEquirectangularToCubeMap(uv.st);

	// Convert the viewing position so it's relative a a rectilinear plane located at (0, 0, -1)
	// and perpendicular to the -Z axis
	mat3 rotI = inverse(rot);
	n = rotI * n;

	// If we are looking away from the rectilinear plane, don't bother outputting anything
	vec3 lookDir = vec3(0, 0, -1);
	if (dot(lookDir, normalize(n)) <= 0)
	{
		fragColor  = vec4(0.0);
		return;
	}

	// Find the intersection between our viewing direction, and the rectilinear plane
	vec3 p = IntersectPlane(normalize(n), vec3(0, 0, 1), vec3(-1, -1, -1));

	float fov = uFOV / 2.0;
	// Now determine where on the recilinear plane our viewing frustum intersects.
	vec3 leftAngle = TDRotateY(radians(-fov)) * vec3(0, 0, -1);
	// This is the bottom left of the viewing frustum on the recilinear plane.
	vec3 leftPoint = IntersectPlane(normalize(leftAngle), vec3(0, 0, 1), vec3(-1, -1, -1));

	float aspectRatio = res.x / res.y;

	// Adjust for aspect ratio.
	// We want coordinates [-1, 1] to be the area of the equirect that gets filled
	// with this input image, so scale them so -1 and 1 are the
	// left/right/bottom/top edges of our view frustum
	p.x /= leftPoint.x;
	p.y /= leftPoint.x / aspectRatio;


	p.xy = applyLensDistortion(uABC.x, uABC.y, uABC.z, p.xy, aspectRatio);


	// apply shear
	p.xy += vec2(p.y * (-uShear.x / float(res.x)), p.x * (-uShear.y / float(res.y)));	


	// Convert to [0,1] coordinates 
	p *= 0.5;
	p += 0.5;
	// Do the shift in these coordinates
	p.xy += uShift / res.xy * vec2(1, -1);

	// Back to normalized to determine edge distances
	vec2 normP = (p.xy - vec2(0.5)) * 2.0;
	float edgeDist = 1.0 - clamp(max(abs(normP.x), abs(normP.y)), 0.0, 1.0);

	if (p.x > 1 || p.y > 1 || p.x < 0 || p.y < 0)
	{
		fragColor = vec4(0.0);
		return;
	}

	// crop the image
	p.x = uCropTexture.x + p.x * (uCropTexture.y-uCropTexture.x);
	p.y = uCropTexture.z + p.y * (uCropTexture.w-uCropTexture.z);

	fragColor = vec4(p.xy, edgeDist, 1.0);
	return;

}
